messages.content:
This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i32 @fold_add_udiv_urem_pow2_no_mul(i32 noundef %arg) {
  %lshr = lshr i32 %arg, 4
  %and = and i32 %arg, 15
  %add = add i32 %lshr, %and
  ret i32 %add
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i32 @fold_add_udiv_urem_pow2_no_mul(i32 noundef %arg) {
  %lshr = lshr i32 %arg, 4
  %and = and i32 %arg, 15
  %add = add nuw nsw i32 %lshr, %and
  ret i32 %add
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp:InstCombinerImpl::SimplifyAddWithRemainder to implement the missed optimization:
```cpp
  Value *Div, *Rem;
  APInt C1, C2;
  if (!LHS->hasOneUse() || !MatchMul(LHS, Div, C1))
    Div = LHS, C1 = APInt(I.getType()->getScalarSizeInBits(), 1);
  if (!RHS->hasOneUse() || !MatchMul(RHS, Rem, C2))
    Rem = RHS, C2 = APInt(I.getType()->getScalarSizeInBits(), 1);
  if (match(Div, m_IRem(m_Value(), m_Value()))) {
    std::swap(Div, Rem);
    std::swap(C1, C2);
  }
  Value *DivOpV;
  APInt DivOpC;
  if (MatchRem(Rem, X, C0, IsSigned) &&
      MatchDiv(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
    APInt NewC = C1 - C2 * C0;
    if (!NewC.isZero() && !Rem->hasOneUse())
      return nullptr;
    if (!isGuaranteedNotToBeUndef(X, &AC, &I, &DT))
      return nullptr;
    Value *MulXC2 = Builder.CreateMul(X, ConstantInt::get(X->getType(), C2));
    if (NewC.isZero())
      return MulXC2;
    return Builder.CreateAdd(
        Builder.CreateMul(Div, ConstantInt::get(X->getType(), NewC)), MulXC2);
  }

  return nullptr;
```

